const manifest = {
  identifier: 'pulse-quest-manager',
  api: [
    {
      url: 'https://n8n.eli.kr/webhook/pulse-command',
      name: 'quest_command',
      description: 'Execute a pulse quest management command. Routes to the n8n W2 webhook handler for all quest operations.',
      parameters: {
        type: 'object',
        properties: {
          action: {
            type: 'string',
            description: 'The command to execute: today, complete, cancel, defer, restore, edit, add, regen, brief, stats, deferred, preview, weekly, help, classify, create_routine',
            enum: [
              'today', 'complete', 'cancel', 'defer', 'restore',
              'edit', 'add', 'regen', 'brief', 'stats',
              'deferred', 'preview', 'weekly', 'help', 'ping',
              'classify', 'create_routine'
            ]
          },
          target: {
            type: 'string',
            description: "Optional target: quest number(s) for interactive commands (e.g., '1,3' or '1-3'), 'all' for /brief all, issue IDs for resolved selections"
          },
          params: {
            type: 'object',
            description: 'Optional parameters: { days: number } for /stats, { name: string, duration: string } for /add, { field: string, value: string } for /edit, { message: string } for /classify and /create_routine, routine fields for /create_routine confirm',
            properties: {
              days: { type: 'number' },
              name: { type: 'string' },
              duration: { type: 'string' },
              field: { type: 'string' },
              value: { type: 'string' },
              priority: { type: 'string' },
              message: { type: 'string', description: 'Natural language input for /classify or /create_routine' },
              active_session: { type: 'boolean', description: 'Whether an interactive session is active (for /classify)' },
              session_action: { type: 'string', description: "The active session's action (for /classify)" },
              routine_name: { type: 'string', description: 'Routine name (for /create_routine confirm)' },
              routine_time: { type: 'string', description: 'Routine time HH:MM (for /create_routine confirm)' },
              routine_duration_min: { type: 'number', description: 'Duration in minutes (for /create_routine confirm)' },
              routine_priority: { type: 'string', description: 'Priority level (for /create_routine confirm)' },
              routine_days: { type: 'array', items: { type: 'string' }, description: 'Days of week (for /create_routine confirm)' },
              routine_mandatory: { type: 'boolean', description: 'Whether routine is mandatory (for /create_routine confirm)' },
              add_today: { type: 'boolean', description: "Whether to add to today's quests (for /create_routine confirm)" },
              target_project_id: { type: 'string', description: 'Target Plane.so project ID (for /create_routine confirm)' }
            }
          }
        },
        required: ['action']
      }
    }
  ],
  gateway: 'https://n8n.eli.kr/webhook/pulse-command',
  version: '1',
  settings: {
    type: 'object',
    properties: {
      apiKey: {
        title: 'API Key',
        type: 'string',
        description: 'n8n webhook authentication key (PULSE_N8N_WEBHOOK_SECRET)',
        format: 'password'
      }
    },
    required: ['apiKey'],
    auth: {
      type: 'header',
      header: {
        key: 'X-API-Key',
        value: '{{apiKey}}'
      }
    }
  },
  meta: {
    title: 'pulse Quest Manager',
    description: 'Daily quest management system powered by Plane.so and n8n',
    avatar: '📋'
  }
};

return [{ json: manifest }];
